136	    private List<StorePlugin> fetchPlugins(String urlStr) throws Exception {
137	        HttpURLConnection conn = (HttpURLConnection) new URL(urlStr).openConnection();
138	        conn.setRequestMethod("GET");
139	        conn.setConnectTimeout(10000);
140	        conn.setReadTimeout(15000);
141	        conn.setRequestProperty("Accept", "application/json");
142	
143	        int responseCode = conn.getResponseCode();
144	        if (responseCode != 200) {
145	            throw new RuntimeException("HTTP " + responseCode);
146	        }
147	
148	        StringBuilder sb = new StringBuilder();
149	        try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
150	            String line;
151	            while ((line = br.readLine()) != null) {
152	                sb.append(line);
153	            }
154	        }
155	
156	        return parsePluginJson(sb.toString());
157	    }
158	
159	    private List<StorePlugin> parsePluginJson(String json) {
160	        List<StorePlugin> result = new ArrayList<>();
161	        // Simple JSON parser for the plugin list array
162	        // Expected format: [{ "id": "...", "name": "...", "description": "...", "version": "...", "jarUrl": "...", "iconStyle": "...", "category": "..." }, ...]
163	        try {
164	            // Find array start
165	            int arrayStart = json.indexOf('[');
166	            int arrayEnd = json.lastIndexOf(']');
167	            if (arrayStart == -1 || arrayEnd == -1) return result;
168	
169	            String arrayContent = json.substring(arrayStart + 1, arrayEnd);
170	            // Split by }{ (avoiding full regex for safety)
171	            String[] objects = arrayContent.split("\\},\\s*\\{");
172	
173	            for (String obj : objects) {
174	                if (!obj.startsWith("{")) obj = "{" + obj;
175	                if (!obj.endsWith("}")) obj = obj + "}";
176	
177	                StorePlugin p = new StorePlugin();
178	                p.id = extractJsonString(obj, "id");
179	                p.name = extractJsonString(obj, "name");
180	                p.description = extractJsonString(obj, "description");
181	                p.version = extractJsonString(obj, "version");
182	                p.jarUrl = extractJsonString(obj, "jarUrl");
183	                p.iconStyle = extractJsonString(obj, "iconStyle", "ic-blue");
184	                p.category = extractJsonString(obj, "category", "other");
185	
186	                if (p.id != null && p.name != null && p.jarUrl != null) {
187	                    result.add(p);
188	                }
189	            }
190	        } catch (Exception e) {
191	            log.warn("JSON parse error, showing partial results", e);
192	        }
193	        return result;
194	    }
195	
196	    private String extractJsonString(String json, String key) {
197	        return extractJsonString(json, key, null);
198	    }
199	
200	    private String extractJsonString(String json, String key, String defaultVal) {
201	        String search = "\"" + key + "\"";
202	        int keyPos = json.indexOf(search);
203	        if (keyPos == -1) return defaultVal;
204	
205	        int colonPos = json.indexOf(':', keyPos);
206	        if (colonPos == -1) return defaultVal;
207	
208	        int valueStart = json.indexOf('"', colonPos + 1);
209	        if (valueStart == -1) return defaultVal;
210	
211	        int valueEnd = json.indexOf('"', valueStart + 1);
212	        if (valueEnd == -1) return defaultVal;
213	
214	        return json.substring(valueStart + 1, valueEnd);
215	    }
