308	    private void installPlugin(StorePlugin plugin, Button installBtn, ProgressBar progress) {
309	        installBtn.setDisable(true);
310	        progress.setVisible(true);
311	        progress.setProgress(-1);
312	        final ProgressBar finalProgress = progress;
